(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"cash-on-cash-return",fields:[{"key":"annualCashFlow","label":"연간 세전 현금흐름","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"cashInvested","label":"실제 투입 현금","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var f=Number(x.annualCashFlow),c=Number(x.cashInvested);if(![f,c].every(Number.isFinite)||c<=0)return{error:"실제 투입 현금은 0보다 커야 합니다."};return{rate:f/c*100,monthly:f/12};},format:function(r,api){return api.resultCard("현금투자수익률",api.formatNumber(r.rate,4)+"%","")+api.resultCard("월평균 현금흐름",api.formatWon(r.monthly),"");}},{id:"debt-service-coverage-ratio",fields:[{"key":"noi","label":"연간 순영업소득 NOI","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"debtService","label":"연간 원리금 상환액","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"금융기관별 심사 기준은 다를 수 있습니다.",compute:function(x){var n=Number(x.noi),d=Number(x.debtService);if(![n,d].every(Number.isFinite)||d<=0)return{error:"연간 원리금 상환액은 0보다 커야 합니다."};return{ratio:n/d,margin:n-d};},format:function(r,api){return api.resultCard("DSCR",api.formatNumber(r.ratio,4),"")+api.resultCard("상환 후 잔여소득",api.formatWon(r.margin),"");}},{id:"rent-increase",fields:[{"key":"currentRent","label":"현재 월세","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"increaseRate","label":"인상률 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"법정 인상 한도나 계약 조건은 별도로 확인해야 합니다.",compute:function(x){var c=Number(x.currentRent),r=Number(x.increaseRate)/100;if(![c,r].every(Number.isFinite)||c<0||r<0)return{error:"입력값은 0 이상이어야 합니다."};var n=c*(1+r),diff=n-c;return{newRent:n,monthlyIncrease:diff,annualIncrease:diff*12};},format:function(r,api){return api.resultCard("인상 후 월세",api.formatWon(r.newRent),"")+api.resultCard("월 추가 부담",api.formatWon(r.monthlyIncrease),"")+api.resultCard("연 추가 부담",api.formatWon(r.annualIncrease),"");}},{id:"ev-charging-time",fields:[{"key":"capacity","label":"배터리 용량 (kWh)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"start","label":"현재 충전량 (%)","type":"number","placeholder":"","default":"20","options":[],"raw":false},{"key":"target","label":"목표 충전량 (%)","type":"number","placeholder":"","default":"80","options":[],"raw":false},{"key":"charger","label":"충전기 출력 (kW)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"efficiency","label":"충전 효율 (%)","type":"number","placeholder":"","default":"90","options":[],"raw":false}],hint:"충전 곡선과 온도·차량 제한으로 실제 시간은 더 길어질 수 있습니다.",compute:function(x){var c=Number(x.capacity),s=Number(x.start)/100,t=Number(x.target)/100,p=Number(x.charger),e=Number(x.efficiency)/100;if(![c,s,t,p,e].every(Number.isFinite)||c<=0||s<0||t<=s||t>1||p<=0||e<=0||e>1)return{error:"목표 충전량은 현재보다 크고 100% 이하여야 하며 출력·효율은 0보다 커야 합니다."};var energy=c*(t-s),hours=energy/(p*e);return{energy:energy,hours:hours,minutes:hours*60};},format:function(r,api){var h=Math.floor(r.minutes/60),m=Math.round(r.minutes-h*60);return api.resultCard("예상 충전시간",h+"시간 "+m+"분","")+api.resultCard("필요 충전 에너지",api.formatNumber(r.energy,3)+"kWh","");}},{id:"tire-size-comparison",fields:[{"key":"oldWidth","label":"기존 폭 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"oldAspect","label":"기존 편평비 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"oldRim","label":"기존 휠 (inch)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"newWidth","label":"신규 폭 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"newAspect","label":"신규 편평비 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"newRim","label":"신규 휠 (inch)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"shownSpeed","label":"속도계 표시속도 (km/h)","type":"number","placeholder":"","default":"100","options":[],"raw":false}],hint:"차량 제조사의 허용 규격과 간섭 여부를 반드시 별도로 확인하세요.",compute:function(x){var ow=Number(x.oldWidth),oa=Number(x.oldAspect),or=Number(x.oldRim),nw=Number(x.newWidth),na=Number(x.newAspect),nr=Number(x.newRim),sp=Number(x.shownSpeed);if(![ow,oa,or,nw,na,nr,sp].every(Number.isFinite)||ow<=0||oa<=0||or<=0||nw<=0||na<=0||nr<=0||sp<0)return{error:"타이어 규격은 0보다 크게 입력해 주세요."};function dia(w,a,r){return r*25.4+2*w*a/100;}var od=dia(ow,oa,or),nd=dia(nw,na,nr),diff=(nd-od)/od*100,actual=sp*nd/od;return{oldDiameter:od,newDiameter:nd,difference:diff,actualSpeed:actual};},format:function(r,api){return api.resultCard("외경 차이",api.formatNumber(r.difference,3)+"%","")+api.resultCard("예상 실제속도",api.formatNumber(r.actualSpeed,2)+"km/h","")+api.resultCard("기존·신규 외경",api.formatNumber(r.oldDiameter,1)+" / "+api.formatNumber(r.newDiameter,1)+"mm","");}},{id:"vehicle-depreciation",fields:[{"key":"purchasePrice","label":"구매가격","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"annualRate","label":"연평균 감가율 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"years","label":"보유기간 (년)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"실제 중고차 가격은 주행거리·사고이력·수요·차종에 따라 달라집니다.",compute:function(x){var p=Number(x.purchasePrice),r=Number(x.annualRate)/100,y=Number(x.years);if(![p,r,y].every(Number.isFinite)||p<0||r<0||r>=1||y<0)return{error:"감가율은 0 이상 100% 미만이어야 합니다."};var value=p*Math.pow(1-r,y);return{value:value,loss:p-value,retention:p===0?0:value/p*100};},format:function(r,api){return api.resultCard("예상 잔존가치",api.formatWon(r.value),"")+api.resultCard("누적 감가액",api.formatWon(r.loss),"")+api.resultCard("가치 유지율",api.formatNumber(r.retention,2)+"%","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
